`IFormFile` buffers the entire request body into memory by default. For large files, read the raw request body stream directly and write to disk in chunks:

```csharp
// Program.cs
var builder = WebApplication.CreateBuilder(args);

// Raise the request body size limit (default is ~28MB)
builder.WebHost.ConfigureKestrel(o =>
    o.Limits.MaxRequestBodySize = 2L * 1024 * 1024 * 1024); // 2 GB

var app = builder.Build();

app.MapPost("/upload", async (HttpRequest request) =>
{
    // Disable request buffering so ASP.NET doesn't load it all into memory
    request.EnableBuffering(bufferThreshold: 1024 * 64);

    var boundary = request.GetMultipartBoundary();
    if (string.IsNullOrEmpty(boundary))
        return Results.BadRequest("Missing multipart boundary");

    var reader = new Microsoft.AspNetCore.WebUtilities.MultipartReader(boundary, request.Body);
    MultipartSection? section;

    while ((section = await reader.ReadNextSectionAsync()) != null)
    {
        if (!Microsoft.Net.Http.Headers.ContentDispositionHeaderValue
                .TryParse(section.ContentDisposition, out var contentDisposition)
            || !contentDisposition.IsFileDisposition())
        {
            continue;
        }

        var fileName = Path.GetRandomFileName(); // safe name
        var savePath = Path.Combine("/tmp/uploads", fileName);

        await using var fileStream = new FileStream(
            savePath, FileMode.Create, FileAccess.Write, FileShare.None,
            bufferSize: 81920, useAsync: true);

        // Streams chunk-by-chunk â€” never holds the whole file in memory
        await section.Body.CopyToAsync(fileStream);
    }

    return Results.Ok("Upload complete");
})
.DisableAntiforgery();

app.Run();
```

**Key points:**

| Problem | Fix |
|---------|-----|
| Default 28 MB body limit | Set `MaxRequestBodySize` on Kestrel |
| `IFormFile` buffers to RAM | Use `MultipartReader` to stream sections |
| Memory pressure | `CopyToAsync` streams in ~80 KB chunks |

**Also disable the form size limit** if you use `[RequestFormLimits]` or the options API:

```csharp
builder.Services.Configure<FormOptions>(o =>
{
    o.MultipartBodyLengthLimit = 2L * 1024 * 1024 * 1024;
});
```

**Helper extension** (if `GetMultipartBoundary` isn't resolved):

```csharp
using Microsoft.Net.Http.Headers;

public static class HttpRequestExtensions
{
    public static string? GetMultipartBoundary(this HttpRequest request)
    {
        var mediaType = MediaTypeHeaderValue.Parse(request.ContentType);
        return HeaderUtilities.RemoveQuotes(mediaType.Boundary).Value;
    }
}
```

This pattern keeps memory flat regardless of file sizeâ€”you'll see roughly constant ~80 KB heap usage per concurrent upload instead of the full file size.
